script:
frappe.ui.form.on('Item', {

    refresh(frm) {
        calculate_profit(frm);
    },

    validate(frm) {
        calculate_profit(frm);
    }

});


function calculate_profit(frm) {

    if (!frm.doc.name) {
        return;
    }


    frappe.call({
        method: "frappe.client.get_list",

        args: {
            doctype: "Item Price",
            filters: {
                item_code: frm.doc.name
            },
            fields: [
                "selling",
                "buying",
                "price_list_rate"
            ],
            limit_page_length: 100
        },

        callback: function(r) {

            if (!r.message) {
                return;
            }


            let buying_price = 0;
            let selling_price = 0;


            r.message.forEach(row => {

                if (row.buying == 1) {
                    buying_price = row.price_list_rate;
                }


                if (row.selling == 1) {
                    selling_price = row.price_list_rate;
                }

            });


            let profit = selling_price - buying_price;


            if (frm.doc.custom_profit_in_item != profit) {
                frm.set_value("custom_profit_in_item", profit, null, true);
            }

        }
    });

}
